def parse_tags(raw: str) -> list[str]:
    if not raw:
        return []
    # Разделяем по запятой, приводим к нижнему регистру и удаляем пробелы
    tags = [tag.strip().lower() for tag in raw.split(',')]
    # Фильтруем пустые строки и дедуплицируем через set, затем сортируем
    return sorted({tag for tag in tags if tag})

